import React, { useState, useEffect, useCallback } from 'react';
import { Search, Phone, Mail, MapPin, Clock, Building, Filter, User, Plus, Edit, Trash2, Eye, EyeOff } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { complaintCategories, getCategoryLabel } from '../complaints/complaintCategories';
import toast from 'react-hot-toast';

const WorkersList = () => {
  const { api, user } = useAuth();
  const [workers, setWorkers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('');
  const [filterDepartment, setFilterDepartment] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [categoryAddTarget, setCategoryAddTarget] = useState(null);
  const [selectedWorker, setSelectedWorker] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phoneNumber: '',
    department: '',
    specialization: '',
    designation: '',
    officeLocation: '',
    workHours: '',
    workerType: 'TECHNICAL',
    active: true
  });

  // Pagination state
  const [currentPage, setCurrentPage] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [totalElements, setTotalElements] = useState(0);
  const [pageSize, setPageSize] = useState(1000);

  useEffect(() => {
    fetchWorkers();
  }, [currentPage, pageSize]);

  const handlePageChange = (newPage) => {
    if (newPage >= 0 && newPage < totalPages) {
      setCurrentPage(newPage);
    }
  };

  const handlePageSizeChange = (newSize) => {
    setPageSize(newSize);
    setCurrentPage(0); // Reset to first page when changing page size
  };

  const fetchWorkers = useCallback(async () => {
    try {
      setLoading(true);

      // Ensure currentPage is a valid number
      const safeCurrentPage = typeof currentPage === 'number' && !isNaN(currentPage) ? currentPage : 0;
      const safePageSize = typeof pageSize === 'number' && !isNaN(pageSize) ? pageSize : 10;

      let endpoint;
      if (user?.role === 'ADMIN' || user?.role === 'OWNER') {
        endpoint = `/workers?page=${safeCurrentPage}&size=${safePageSize}&sort=name,asc`;
      } else {
        endpoint = `/workers/active?page=${safeCurrentPage}&size=${safePageSize}&sort=name,asc`;
      }

      const response = await api.get(endpoint);

      // Handle paginated response
      if (response.data.content) {
        setWorkers(response.data.content);
        setTotalPages(response.data.totalPages);
        setTotalElements(response.data.totalElements);
        // Only update currentPage if it's different from the response
        if (response.data.page !== currentPage) {
          setCurrentPage(response.data.page);
        }
      } else {
        // Fallback for non-paginated response
        setWorkers(Array.isArray(response.data) ? response.data : []);
        setTotalPages(1);
        setTotalElements(response.data.length);
        if (currentPage !== 0) {
          setCurrentPage(0);
        }
      }
    } catch (error) {
      console.error('Error fetching workers:', error);
      console.error('Error response:', error.response);
      console.error('Error status:', error.response?.status);
      console.error('Error data:', error.response?.data);
      toast.error('Failed to fetch workers');
      setWorkers([]);
      setTotalPages(0);
      setTotalElements(0);
    } finally {
      setLoading(false);
    }
  }, [api, user, currentPage, pageSize]);

  useEffect(() => {
    fetchWorkers();
  }, [fetchWorkers]);

  const handleSearch = async () => {
    try {
      setLoading(true);
      if (searchTerm) {
        const activeOnly = !(user?.role === 'ADMIN' || user?.role === 'OWNER');
        const response = await api.get(`/workers/search?keyword=${encodeURIComponent(searchTerm)}&activeOnly=${activeOnly}`);
        setWorkers(Array.isArray(response.data) ? response.data : []);
      } else {
        fetchWorkers();
      }
    } catch (error) {
      console.error('Error searching workers:', error);
      toast.error('Failed to search workers');
      setWorkers([]);
    } finally {
      setLoading(false);
    }
  };

  const handleFilter = async () => {
    try {
      setLoading(true);
      let url = '/workers/active';

      if (filterType) {
        url = `/workers/type/${filterType}`;
      }

      if (filterDepartment) {
        url = `/workers/department/${encodeURIComponent(filterDepartment)}`;
      }

      const response = await api.get(url);
      setWorkers(response.data.content || response.data);
    } catch (error) {
      console.error('Error filtering workers:', error);
    } finally {
      setLoading(false);
    }
  };

  const clearFilters = () => {
    setSearchTerm('');
    setFilterType('');
    setFilterDepartment('');
    fetchWorkers();
  };

  const handleCreateWorker = async (e) => {
    e.preventDefault();
    try {
      await api.post('/workers', formData);
      toast.success('Worker created successfully');
      setShowCreateModal(false);
      setFormData({
        name: '',
        email: '',
        phoneNumber: '',
        department: '',
        specialization: '',
        designation: '',
        officeLocation: '',
        workHours: '',
        workerType: 'TECHNICAL',
        active: true
      });
      fetchWorkers();
    } catch (error) {
      console.error('Error creating worker:', error);
      toast.error(error.response?.data?.message || 'Failed to create worker');
    }
  };

  const handleUpdateWorker = async (e) => {
    e.preventDefault();
    try {
      await api.put(`/workers/${selectedWorker.id}`, formData);
      toast.success('Worker updated successfully');
      setShowEditModal(false);
      setSelectedWorker(null);
      fetchWorkers();
    } catch (error) {
      console.error('Error updating worker:', error);
      toast.error(error.response?.data?.message || 'Failed to update worker');
    }
  };

  const handleDeleteWorker = async (id) => {
    if (window.confirm('Are you sure you want to delete this worker?')) {
      try {
        await api.delete(`/workers/${id}`);
        toast.success('Worker deleted successfully');
        fetchWorkers();
      } catch (error) {
        console.error('Error deleting worker:', error);
        toast.error('Failed to delete worker');
      }
    }
  };

  const handleToggleActive = async (id, active) => {
    try {
      await api.put(`/workers/${id}/${active ? 'activate' : 'deactivate'}`);
      toast.success(`Worker ${active ? 'activated' : 'deactivated'} successfully`);
      fetchWorkers();
    } catch (error) {
      console.error('Error toggling worker status:', error);
      toast.error('Failed to update worker status');
    }
  };

  const openEditModal = (worker) => {
    setSelectedWorker(worker);
    setFormData({
      name: worker.name,
      email: worker.email,
      phoneNumber: worker.phoneNumber,
      department: worker.department || '',
      specialization: worker.specialization || '',
      designation: worker.designation || '',
      officeLocation: worker.officeLocation || '',
      workHours: worker.workHours || '',
      workerType: worker.workerType || 'TECHNICAL',
      active: worker.active
    });
    setShowEditModal(true);
  };

  const filteredWorkers = workers.filter(worker => {
    const matchesSearch = !searchTerm || 
      worker.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      worker.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      worker.department?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      worker.specialization?.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesType = !filterType || worker.workerType === filterType;
    const matchesDepartment = !filterDepartment || worker.department === filterDepartment;

    return matchesSearch && matchesType && matchesDepartment;
  });

  const getWorkerTypeColor = (type) => {
    const colors = {
      'TECHNICAL': 'bg-blue-100 text-blue-800',
      'ELECTRICAL': 'bg-yellow-100 text-yellow-800',
      'PLUMBING': 'bg-cyan-100 text-cyan-800',
      'CARPENTRY': 'bg-amber-100 text-amber-800',
      'MAINTENANCE': 'bg-green-100 text-green-800',
      'IT': 'bg-purple-100 text-purple-800',
      'LAB': 'bg-indigo-100 text-indigo-800',
      'HOUSEKEEPING': 'bg-pink-100 text-pink-800',
      'SECURITY': 'bg-red-100 text-red-800',
      'OTHER': 'bg-gray-100 text-gray-800'
    };
    return colors[type] || 'bg-gray-100 text-gray-800';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto p-6">
      {/* Header Banner */}
      <div className="bg-white rounded-xl p-8 shadow-sm border border-gray-200 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-6 overflow-hidden relative mb-8">
        <div className="relative z-10">
          <h1 className="text-3xl font-bold mb-2 text-gray-900">Worker Directory</h1>
          <p className="text-gray-500 italic">Find and contact maintenance workers for infrastructure issues</p>
        </div>
        {(user?.role === 'ADMIN' || user?.role === 'OWNER') && (
          <button
            onClick={() => setShowCreateModal(true)}
            className="relative z-10 bg-primary-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-primary-700 transition-all duration-300 shadow-md flex items-center justify-center space-x-2"
          >
            <Plus className="h-5 w-5" />
            <span>Add Worker</span>
          </button>
        )}
        {/* Background decorative blur */}
        <div className="absolute top-0 right-0 -mr-16 -mt-16 h-48 w-48 rounded-full bg-slate-100/40 blur-3xl"></div>
      </div>

      {/* Search and Filters */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 mb-6">
        <div className="flex flex-col lg:flex-row gap-4 mb-4">
          <div className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-5 w-5" />
              <input
                type="text"
                placeholder="Search workers by name, email, department..."
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
              />
            </div>
          </div>
          <div className="flex gap-2">
            <button
              onClick={handleSearch}
              className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors"
            >
              Search
            </button>
            <button
              onClick={() => setShowFilters(!showFilters)}
              className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors flex items-center gap-2"
            >
              <Filter className="h-4 w-4" />
              Filters
            </button>
            {(searchTerm || filterType || filterDepartment) && (
              <button
                onClick={clearFilters}
                className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors"
              >
                Clear
              </button>
            )}
          </div>
        </div>

        {/* Advanced Filters */}
        {showFilters && (
          <div className="border-t border-gray-200 pt-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Worker Type</label>
                <select
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  value={filterType}
                  onChange={(e) => setFilterType(e.target.value)}
                >
                  <option value="">All Types</option>
                  <option value="TECHNICAL">Technical Staff</option>
                  <option value="ELECTRICAL">Electrical</option>
                  <option value="PLUMBING">Plumbing</option>
                  <option value="CARPENTRY">Carpentry</option>
                  <option value="MAINTENANCE">Maintenance</option>
                  <option value="IT">IT Support</option>
                  <option value="LAB">Lab Technician</option>
                  <option value="HOUSEKEEPING">Housekeeping</option>
                  <option value="SECURITY">Security</option>
                  <option value="OTHER">Other</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Department</label>
                <input
                  type="text"
                  placeholder="Enter department name"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                  value={filterDepartment}
                  onChange={(e) => setFilterDepartment(e.target.value)}
                />
              </div>
            </div>
            <div className="mt-4 flex gap-2">
              <button
                onClick={handleFilter}
                className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors"
              >
                Apply Filters
              </button>
              <button
                onClick={clearFilters}
                className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors"
              >
                Reset
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Workers Grid */}
      {filteredWorkers.length === 0 ? (
        <div className="text-center py-12">
          <User className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No workers found</h3>
          <p className="text-gray-500">Try adjusting your search or filters</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredWorkers.map((worker) => (
            <div key={worker.id} className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 hover:shadow-md transition-shadow">
              {/* Worker Header */}
              <div className="flex items-start justify-between mb-4">
                <Link
                  to={(user?.role === 'ADMIN' || user?.role === 'OWNER') ? `/workers/${worker.id}` : '#'}
                  className={`flex items-center space-x-3 ${(user?.role === 'ADMIN' || user?.role === 'OWNER') ? 'cursor-pointer group' : ''}`}
                >
                  <div className="w-12 h-12 bg-primary-100 rounded-full flex items-center justify-center group-hover:bg-primary-200 transition-colors">
                    <User className="h-6 w-6 text-primary-600" />
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900 group-hover:text-primary-600 transition-colors">{worker.name}</h3>
                    <p className="text-sm text-gray-600">{worker.designation || 'Staff Member'}</p>
                  </div>
                </Link>
                <span className={`px-2 py-1 text-xs font-medium rounded-full ${getWorkerTypeColor(worker.workerType)}`}>
                  {worker.workerType?.replace('_', ' ') || 'OTHER'}
                </span>
              </div>

              {/* Contact Information */}
              <div className="space-y-3">
                {worker.phoneNumber && (
                  <div className="flex items-center space-x-3">
                    <Phone className="h-4 w-4 text-gray-400" />
                    <div>
                      <p className="text-sm font-medium text-gray-900">Phone</p>
                      <a href={`tel:${worker.phoneNumber}`} className="text-sm text-primary-600 hover:text-primary-700">
                        {worker.phoneNumber}
                      </a>
                    </div>
                  </div>
                )}

                {worker.email && (
                  <div className="flex items-center space-x-3">
                    <Mail className="h-4 w-4 text-gray-400" />
                    <div>
                      <p className="text-sm font-medium text-gray-900">Email</p>
                      <a href={`mailto:${worker.email}`} className="text-sm text-primary-600 hover:text-primary-700">
                        {worker.email}
                      </a>
                    </div>
                  </div>
                )}

                {worker.department && (
                  <div className="flex items-center space-x-3">
                    <Building className="h-4 w-4 text-gray-400" />
                    <div>
                      <p className="text-sm font-medium text-gray-900">Department</p>
                      <p className="text-sm text-gray-600">{worker.department}</p>
                    </div>
                  </div>
                )}

                {worker.officeLocation && (
                  <div className="flex items-center space-x-3">
                    <MapPin className="h-4 w-4 text-gray-400" />
                    <div>
                      <p className="text-sm font-medium text-gray-900">Office Location</p>
                      <p className="text-sm text-gray-600">{worker.officeLocation}</p>
                    </div>
                  </div>
                )}

                {worker.workHours && (
                  <div className="flex items-center space-x-3">
                    <Clock className="h-4 w-4 text-gray-400" />
                    <div>
                      <p className="text-sm font-medium text-gray-900">Work Hours</p>
                      <p className="text-sm text-gray-600">{worker.workHours}</p>
                    </div>
                  </div>
                )}

                {worker.specialization && (
                  <div className="pt-3 border-t border-gray-100">
                    <p className="text-sm font-medium text-gray-900 mb-1">Specialization</p>
                    <p className="text-sm text-gray-600">{worker.specialization}</p>
                  </div>
                )}

                {/* Admin Actions */}
                {(user?.role === 'ADMIN' || user?.role === 'OWNER') && (
                  <div className="pt-3 border-t border-gray-100 mt-4">
                    <div className="flex items-center justify-between">
                      <span className={`px-2 py-1 text-xs font-medium rounded-full ${
                        worker.active ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                      }`}>
                        {worker.active ? 'Active' : 'Inactive'}
                      </span>
                      <div className="flex items-center space-x-2">
                        <button
                          onClick={() => openEditModal(worker)}
                          className="text-primary-600 hover:text-primary-900"
                          title="Edit Worker"
                        >
                          <Edit className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleToggleActive(worker.id, !worker.active)}
                          className={`${worker.active ? 'text-yellow-600 hover:text-yellow-900' : 'text-green-600 hover:text-green-900'}`}
                          title={worker.active ? 'Deactivate' : 'Activate'}
                        >
                          {worker.active ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                        </button>
                        <button
                          onClick={() => handleDeleteWorker(worker.id)}
                          className="text-red-600 hover:text-red-900"
                          title="Delete Worker"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Create/Edit Modal */}
      {(showCreateModal || showEditModal) && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <h2 className="text-xl font-bold mb-4">
              {showCreateModal ? 'Create New Worker' : 'Edit Worker'}
            </h2>
            <form onSubmit={showCreateModal ? handleCreateWorker : handleUpdateWorker}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Name *</label>
                  <input
                    type="text"
                    required
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Email *</label>
                  <input
                    type="email"
                    required
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.email}
                    onChange={(e) => setFormData({...formData, email: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Phone Number *</label>
                  <input
                    type="tel"
                    required
                    pattern="[0-9]{10}"
                    placeholder="10 digit phone number"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.phoneNumber}
                    onChange={(e) => setFormData({...formData, phoneNumber: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Designation</label>
                  <input
                    type="text"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.designation}
                    onChange={(e) => setFormData({...formData, designation: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Department</label>
                  <input
                    type="text"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.department}
                    onChange={(e) => setFormData({...formData, department: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Worker Type</label>
                  <select
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.workerType}
                    onChange={(e) => setFormData({...formData, workerType: e.target.value})}
                  >
                    <option value="TECHNICAL">Technical Staff</option>
                    <option value="ELECTRICAL">Electrical</option>
                    <option value="PLUMBING">Plumbing</option>
                    <option value="CARPENTRY">Carpentry</option>
                    <option value="MAINTENANCE">Maintenance</option>
                    <option value="IT">IT Support</option>
                    <option value="LAB">Lab Technician</option>
                    <option value="HOUSEKEEPING">Housekeeping</option>
                    <option value="SECURITY">Security</option>
                    <option value="OTHER">Other</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Office Location</label>
                  <input
                    type="text"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.officeLocation}
                    onChange={(e) => setFormData({...formData, officeLocation: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Work Hours</label>
                  <input
                    type="text"
                    placeholder="e.g., 9:00 AM - 5:00 PM"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.workHours}
                    onChange={(e) => setFormData({...formData, workHours: e.target.value})}
                  />
                </div>
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-2">Specialization</label>
                  <textarea
                    rows="2"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                    value={formData.specialization}
                    onChange={(e) => setFormData({...formData, specialization: e.target.value})}
                  />
                </div>
                <div className="md:col-span-2">
                  <label className="flex items-center">
                    <input
                      type="checkbox"
                      className="rounded border-gray-300 text-primary-600 focus:ring-primary-500"
                      checked={formData.active}
                      onChange={(e) => setFormData({...formData, active: e.target.checked})}
                    />
                    <span className="ml-2 text-sm text-gray-700">Active</span>
                  </label>
                </div>
              </div>
              <div className="flex justify-end space-x-2 mt-6">
                <button
                  type="button"
                  onClick={() => {
                    showCreateModal ? setShowCreateModal(false) : setShowEditModal(false);
                    setSelectedWorker(null);
                  }}
                  className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700"
                >
                  {showCreateModal ? 'Create' : 'Update'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default WorkersList;
